func WithAttempt(r *http.Request, attempt int) *http.Request {
    ctx := context.WithValue(r.Context(), Attempts, attempt)
    return r.WithContext(ctx)
}

func main() {
    r, _ := http.NewRequest("GET", "http://localhost/", nil)

    r2 := WithAttempt(r, 2)
    fmt.Println(GetAttemptsFromContext(r2)) // 2
    fmt.Println(GetAttemptsFromContext(r))  // 0 — original unchanged

    r3 := WithAttempt(r2, 3)
    fmt.Println(GetAttemptsFromContext(r3)) // 3
    fmt.Println(GetAttemptsFromContext(r2)) // 2 — r2 unchanged
}
